sql:
SELECT u.username, u.email
FROM users u
WHERE u.user_id NOT IN (SELECT o.user_id FROM orders o);

SELECT category_name 
FROM categories 
WHERE category_id > 5;

external_knowledge:
- 'identities and the monetary reflections' refers to order_id and total_amount;
- 'floating in the void' means the orders have no shipping record (shipping_id IS NULL);
- 'tether of a specific payment method' refers to the payment method used for payment;
- 'before they find their way to the realm of the dispatched' indicates that the orders have not yet been shipped.
